import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import './Dashboard.css';

export default function AdminDashboard() {
  const [complaints, setComplaints] = useState([]);
  const [filterCategory, setFilterCategory] = useState('all');
  const [filterStatus, setFilterStatus] = useState('all');
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({
    total: 0,
    pending: 0,
    inProgress: 0,
    resolved: 0,
    highPriority: 0
  });
  const [selectedComplaint, setSelectedComplaint] = useState(null);
  const [showDetails, setShowDetails] = useState(false);
  
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const user = JSON.parse(localStorage.getItem('user'));

  useEffect(() => {
    if (!token || user?.role !== 'admin') {
      navigate('/login');
      return;
    }
    fetchComplaints();
  }, [filterCategory, filterStatus]);

  const fetchComplaints = async () => {
    try {
      const params = new URLSearchParams();
      if (filterCategory !== 'all') params.append('category', filterCategory);
      if (filterStatus !== 'all') params.append('status', filterStatus);
      
      const url = `/api/complaints${params.toString() ? '?' + params.toString() : ''}`;
      const res = await axios.get(url, { headers: { 'x-auth-token': token } });
      
      setComplaints(res.data);
      
      // Calculate comprehensive stats
      const total = res.data.length;
      const pending = res.data.filter(c => c.status === 'pending').length;
      const inProgress = res.data.filter(c => c.status === 'in-progress').length;
      const resolved = res.data.filter(c => c.status === 'resolved').length;
      const highPriority = res.data.filter(c => c.priority === 'high').length;
      
      setStats({ total, pending, inProgress, resolved, highPriority });
      
    } catch (err) {
      console.error('Error fetching complaints:', err);
    } finally {
      setLoading(false);
    }
  };

  const updateStatus = async (id, status) => {
    try {
      await axios.put(`/api/complaints/${id}`, 
        { status }, 
        { headers: { 'x-auth-token': token } }
      );
      fetchComplaints();
    } catch (err) {
      alert('Failed to update status');
    }
  };

  const viewDetails = (complaint) => {
    setSelectedComplaint(complaint);
    setShowDetails(true);
  };

  const logout = () => { 
    localStorage.clear(); 
    navigate('/login'); 
  };

  const formatDate = (date) => {
    return new Date(date).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  const getStatusBadge = (status) => {
    const badges = {
      'pending': { class: 'status-pending', icon: '⏳' },
      'in-progress': { class: 'status-progress', icon: '🔄' },
      'resolved': { class: 'status-resolved', icon: '✅' }
    };
    return badges[status] || badges.pending;
  };

  const getPriorityBadge = (priority) => {
    const badges = {
      'low': { class: 'priority-low', icon: '🟢' },
      'medium': { class: 'priority-medium', icon: '🟡' },
      'high': { class: 'priority-high', icon: '🔴' }
    };
    return badges[priority] || badges.medium;
  };

  if (loading) {
    return (
      <div className="admin-loading">
        <div className="spinner"></div>
        <p>Loading admin dashboard...</p>
      </div>
    );
  }

  return (
    <div className="admin-dashboard">
      {/* Sidebar */}
      <div className="admin-sidebar">
        <div className="sidebar-header">
          <div className="logo">
            <h1>🏠 Hostel<span>Hub</span></h1>
            <p>Admin Panel</p>
          </div>
          <div className="admin-profile">
            <div className="admin-avatar">
              {user?.name?.charAt(0) || 'A'}
            </div>
            <div className="admin-info">
              <span className="admin-name">{user?.name || 'Admin'}</span>
              <span className="admin-role">Administrator</span>
            </div>
          </div>
        </div>

        <div className="sidebar-nav">
          <div className="nav-item active">
            <span className="nav-icon">📊</span>
            <span>Dashboard</span>
          </div>
          <div className="nav-item">
            <span className="nav-icon">📋</span>
            <span>All Complaints</span>
          </div>
          <div className="nav-item">
            <span className="nav-icon">👥</span>
            <span>Students</span>
          </div>
          <div className="nav-item">
            <span className="nav-icon">⚙️</span>
            <span>Settings</span>
          </div>
        </div>

        <div className="sidebar-footer">
          <button onClick={logout} className="logout-btn">
            <span>🚪</span> Logout
          </button>
        </div>
      </div>

      {/* Main Content */}
      <div className="admin-main">
        {/* Header */}
        <header className="admin-header">
          <h1>Dashboard Overview</h1>
          <div className="header-actions">
            <div className="date-display">
              📅 {new Date().toLocaleDateString('en-US', { 
                weekday: 'long', 
                year: 'numeric', 
                month: 'long', 
                day: 'numeric' 
              })}
            </div>
            <button className="refresh-btn" onClick={fetchComplaints}>
              🔄 Refresh
            </button>
          </div>
        </header>

        {/* Stats Cards */}
        <div className="stats-grid">
          <div className="stat-card total">
            <div className="stat-icon">📊</div>
            <div className="stat-content">
              <span className="stat-value">{stats.total}</span>
              <span className="stat-label">Total Complaints</span>
            </div>
          </div>
          <div className="stat-card pending">
            <div className="stat-icon">⏳</div>
            <div className="stat-content">
              <span className="stat-value">{stats.pending}</span>
              <span className="stat-label">Pending</span>
            </div>
          </div>
          <div className="stat-card progress">
            <div className="stat-icon">🔄</div>
            <div className="stat-content">
              <span className="stat-value">{stats.inProgress}</span>
              <span className="stat-label">In Progress</span>
            </div>
          </div>
          <div className="stat-card resolved">
            <div className="stat-icon">✅</div>
            <div className="stat-content">
              <span className="stat-value">{stats.resolved}</span>
              <span className="stat-label">Resolved</span>
            </div>
          </div>
          <div className="stat-card urgent">
            <div className="stat-icon">🔴</div>
            <div className="stat-content">
              <span className="stat-value">{stats.highPriority}</span>
              <span className="stat-label">High Priority</span>
            </div>
          </div>
        </div>

        {/* Filters */}
        <div className="filters-section">
          <div className="filters">
            <div className="filter-group">
              <label>Category:</label>
              <select value={filterCategory} onChange={(e) => setFilterCategory(e.target.value)}>
                <option value="all">All Categories</option>
                <option value="plumbing">🚰 Plumbing</option>
                <option value="electrical">⚡ Electrical</option>
                <option value="carpentry">🪑 Carpentry</option>
                <option value="cleaning">🧹 Cleaning</option>
                <option value="other">📌 Other</option>
              </select>
            </div>
            <div className="filter-group">
              <label>Status:</label>
              <select value={filterStatus} onChange={(e) => setFilterStatus(e.target.value)}>
                <option value="all">All Status</option>
                <option value="pending">⏳ Pending</option>
                <option value="in-progress">🔄 In Progress</option>
                <option value="resolved">✅ Resolved</option>
              </select>
            </div>
            <button className="clear-filters" onClick={() => {
              setFilterCategory('all');
              setFilterStatus('all');
            }}>
              Clear Filters
            </button>
          </div>
          <div className="results-count">
            Showing <strong>{complaints.length}</strong> complaints
          </div>
        </div>

        {/* Complaints Table */}
        <div className="complaints-table-container">
          <table className="complaints-table">
            <thead>
              <tr>
                <th>ID</th>
                <th>Student</th>
                <th>Category</th>
                <th>Description</th>
                <th>Priority</th>
                <th>Status</th>
                <th>Submitted</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {complaints.map(complaint => {
                const statusBadge = getStatusBadge(complaint.status);
                const priorityBadge = getPriorityBadge(complaint.priority);
                
                return (
                  <tr key={complaint._id} className={complaint.priority === 'high' ? 'high-priority' : ''}>
                    <td className="complaint-id">#{complaint._id.slice(-6)}</td>
                    <td>
                      <div className="student-cell">
                        <span className="student-name">{complaint.student?.name}</span>
                        <span className="student-email">{complaint.student?.email}</span>
                        <span className="student-room">Room: {complaint.student?.roomNumber}</span>
                      </div>
                    </td>
                    <td>
                      <span className="category-badge">{complaint.category}</span>
                    </td>
                    <td className="description-cell">
                      <div className="description" title={complaint.description}>
                        {complaint.description.length > 50 
                          ? complaint.description.substring(0, 50) + '...' 
                          : complaint.description}
                      </div>
                    </td>
                    <td>
                      <span className={`priority-badge ${priorityBadge.class}`}>
                        {priorityBadge.icon} {complaint.priority}
                      </span>
                    </td>
                    <td>
                      <span className={`status-badge ${statusBadge.class}`}>
                        {statusBadge.icon} {complaint.status}
                      </span>
                    </td>
                    <td>
                      <div className="date-cell">
                        {formatDate(complaint.createdAt)}
                      </div>
                    </td>
                    <td>
                      <div className="action-buttons">
                        <button 
                          className="view-btn"
                          onClick={() => viewDetails(complaint)}
                          title="View Details"
                        >
                          👁️
                        </button>
                        {complaint.status === 'pending' && (
                          <button 
                            className="start-btn"
                            onClick={() => updateStatus(complaint._id, 'in-progress')}
                            title="Start Working"
                          >
                            ▶️
                          </button>
                        )}
                        {complaint.status === 'in-progress' && (
                          <button 
                            className="resolve-btn"
                            onClick={() => updateStatus(complaint._id, 'resolved')}
                            title="Mark Resolved"
                          >
                            ✅
                          </button>
                        )}
                      </div>
                    </td>
                  </tr>
                );
              })}
              {complaints.length === 0 && (
                <tr>
                  <td colSpan="8" className="no-data">
                    <div className="no-data-content">
                      <span className="icon">📭</span>
                      <p>No complaints found</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Details Modal */}
      {showDetails && selectedComplaint && (
        <div className="modal-overlay" onClick={() => setShowDetails(false)}>
          <div className="modal-content" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h2>Complaint Details</h2>
              <button className="close-btn" onClick={() => setShowDetails(false)}>✕</button>
            </div>
            <div className="modal-body">
              <div className="detail-row">
                <label>Complaint ID:</label>
                <span>#{selectedComplaint._id}</span>
              </div>
              <div className="detail-row">
                <label>Student:</label>
                <span>{selectedComplaint.student?.name} ({selectedComplaint.student?.email})</span>
              </div>
              <div className="detail-row">
                <label>Room:</label>
                <span>{selectedComplaint.student?.roomNumber}</span>
              </div>
              <div className="detail-row">
                <label>Phone:</label>
                <span>{selectedComplaint.student?.phoneNumber}</span>
              </div>
              <div className="detail-row">
                <label>Category:</label>
                <span className="category-badge">{selectedComplaint.category}</span>
              </div>
              <div className="detail-row">
                <label>Priority:</label>
                <span className={`priority-badge ${getPriorityBadge(selectedComplaint.priority).class}`}>
                  {getPriorityBadge(selectedComplaint.priority).icon} {selectedComplaint.priority}
                </span>
              </div>
              <div className="detail-row">
                <label>Status:</label>
                <span className={`status-badge ${getStatusBadge(selectedComplaint.status).class}`}>
                  {getStatusBadge(selectedComplaint.status).icon} {selectedComplaint.status}
                </span>
              </div>
              <div className="detail-row">
                <label>Description:</label>
                <p className="detail-description">{selectedComplaint.description}</p>
              </div>
              <div className="detail-row">
                <label>Submitted:</label>
                <span>{formatDate(selectedComplaint.createdAt)}</span>
              </div>
              <div className="detail-row">
                <label>Last Updated:</label>
                <span>{formatDate(selectedComplaint.updatedAt)}</span>
              </div>
            </div>
            <div className="modal-footer">
              <button className="close-modal-btn" onClick={() => setShowDetails(false)}>Close</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
